using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);
builder.Configuration.AddEnvironmentVariables();

builder.Services.AddSingleton<ResearchTools>();

builder.Services.AddChatClient(chatClientBuilder =>
    chatClientBuilder.UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18",
        new OpenAIClientOptions
        {
            Endpoint = builder.Configuration["AI:Endpoint"] is string endpoint
                ? new Uri(endpoint)
                : null,
        },
        builder.Configuration["AI:ApiKey"]
            ?? throw new InvalidOperationException(
                "Set the AI:ApiKey configuration value (env var AI__ApiKey) to your OpenAI API key.")));

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();
var logger = host.Services.GetRequiredService<ILogger<Program>>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWebAsync),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information (perform multiple searches to get breadth).
        2. Save important findings as notes using the note-taking tool.
        3. Review your notes and produce a well-structured summary of the topic.
        Always cite the sources you found. Be thorough but concise.
        """,
    tools: tools);

Console.WriteLine("╔═══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)         ║");
Console.WriteLine("╚═══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

try
{
    AgentResponse response = await agent.RunAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        session: null,
        options: runOptions);

    Console.WriteLine("═══════════════ SUMMARY ═══════════════");
    Console.WriteLine(response.Text);
    Console.WriteLine("═══════════════════════════════════════");

    if (researchTools.NoteCount > 0)
    {
        Console.WriteLine($"\n📝 Notes collected: {researchTools.NoteCount}");
    }

    if (response.Usage is { } usage)
    {
        logger.LogInformation(
            "Token usage — Input: {Input}, Output: {Output}",
            usage.InputTokenCount,
            usage.OutputTokenCount);
    }
}
catch (Exception ex)
{
    logger.LogError(ex, "Research agent failed");
    Console.WriteLine($"\n❌ Error: {ex.Message}");
    return 1;
}

return 0;

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        Environment.Exit(1);
    }

    return topic;
}

