using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace ResearchAgent;

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
public sealed class ResearchTools
{
    private readonly ILogger<ResearchTools> _logger;
    private readonly HttpClient _httpClient;
    private readonly string? _searchApiKey;
    private readonly string? _searchEngineId;
    private readonly List<NoteEntry> _notes = [];

    public int NoteCount => _notes.Count;

    public ResearchTools(IConfiguration configuration, ILogger<ResearchTools> logger)
    {
        _logger = logger;
        _httpClient = new HttpClient();
        _searchApiKey = configuration["Search:ApiKey"];
        _searchEngineId = configuration["Search:EngineId"];
    }

    [Description("Searches the web for information on a given query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        _logger.LogInformation("🌐 Searching: \"{Query}\" (max {Max} results)", query, maxResults);

        // If a Google Custom Search API key is configured, use it
        if (!string.IsNullOrEmpty(_searchApiKey) && !string.IsNullOrEmpty(_searchEngineId))
        {
            return await SearchWithGoogleAsync(query, maxResults);
        }

        // Fallback: simulated search results for demonstration
        _logger.LogWarning("No Search:ApiKey configured — returning simulated results. " +
                           "Set Search__ApiKey and Search__EngineId env vars for real web search.");
        return GetSimulatedResults(query, maxResults);
    }

    [Description("Saves a research note with a title and content. Use this to record important findings.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content/body of the note")] string content,
        [Description("Optional source URL where this information was found")] string? sourceUrl = null)
    {
        var note = new NoteEntry(title, content, sourceUrl, DateTime.UtcNow);
        _notes.Add(note);
        _logger.LogInformation("📝 Note saved: \"{Title}\"", title);
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes. Use this to review what you've found before writing a summary.")]
    public IReadOnlyList<NoteEntry> GetNotes()
    {
        _logger.LogInformation("📋 Retrieving {Count} notes", _notes.Count);
        return _notes.AsReadOnly();
    }

    private async Task<IReadOnlyList<SearchResult>> SearchWithGoogleAsync(string query, int maxResults)
    {
        var url = $"https://www.googleapis.com/customsearch/v1?key={_searchApiKey}&cx={_searchEngineId}&q={Uri.EscapeDataString(query)}&num={maxResults}";

        try
        {
            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);
            var results = new List<SearchResult>();

            if (response.TryGetProperty("items", out var items))
            {
                foreach (var item in items.EnumerateArray())
                {
                    results.Add(new SearchResult(
                        Title: item.GetProperty("title").GetString() ?? "",
                        Snippet: item.GetProperty("snippet").GetString() ?? "",
                        Url: item.GetProperty("link").GetString() ?? ""));
                }
            }

            return results;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Google search failed for query: {Query}", query);
            return [new SearchResult("Error", $"Search failed: {ex.Message}", "")];
        }
    }

    private static List<SearchResult> GetSimulatedResults(string query, int maxResults)
    {
        // Provide realistic-looking simulated results for demo purposes
        var results = new List<SearchResult>
        {
            new($"Overview of {query} - Wikipedia",
                $"A comprehensive overview of {query}, covering its history, key concepts, and modern applications. " +
                "This article provides foundational knowledge and references to primary sources.",
                $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}"),
            new($"Latest Research on {query} - Nature",
                $"Recent peer-reviewed studies have shed new light on {query}. Researchers found significant " +
                "developments in the field, with implications for both theory and practical applications.",
                "https://www.nature.com/articles/example"),
            new($"{query}: A Complete Guide - TechReview",
                $"Everything you need to know about {query}. This guide covers fundamentals, current trends, " +
                "best practices, and expert opinions from industry leaders.",
                "https://www.techreview.com/guide/example"),
            new($"The Future of {query} - MIT Technology Review",
                $"How {query} is evolving and what experts predict for the next decade. Includes analysis of " +
                "emerging trends, potential disruptions, and areas of opportunity.",
                "https://www.technologyreview.com/future/example"),
            new($"{query} - Stanford Encyclopedia",
                $"An in-depth scholarly analysis of {query}, examining its theoretical underpinnings, " +
                "historical development, and current debates in the academic community.",
                "https://plato.stanford.edu/entries/example"),
        };

        return results.Take(maxResults).ToList();
    }
}

