         logger.LogInformation(
             "Token usage — Input: {Input}, Output: {Output}",
             usage.InputTokenCount,
             usage.OutputTokenCount);
     }
 }
 catch (Exception ex)
 {
     logger.LogError(ex, "Research agent failed");
     Console.WriteLine($"\n❌ Error: {ex.Message}");
     return 1;
 }

 return 0;

 static string PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     var topic = Console.ReadLine()?.Trim();
     if (string.IsNullOrWhiteSpace(topic))
     {
         Console.WriteLine("No topic provided. Exiting.");
         Environment.Exit(1);
     }

     return topic;
 }
